// ============ КОНСТАНТЫ И НАСТРОЙКИ ============
const canvas = document.getElementById('game');
const ctx = canvas.getContext('2d');

const GRID_SIZE = 20;            // размер одной клетки (px)
const TILE_COUNT = canvas.width / GRID_SIZE;   // 20 клеток по каждой оси
const INITIAL_SPEED = 130;       // мс между кадрами при старте

// Цвета
const COLORS = {
    snakeHead: '#0ff',
    snakeBody: '#0b7ecf',
    food:      '#e94560',
    gridLine:  'rgba(255,255,255,0.03)',
};

// ============ СОСТОЯНИЕ ИГРЫ ============
let snake;       // массив сегментов [{x, y}]
let food;        // позиция {x, y}
let direction;   // текущее направление {x, y}
let nextDirection; // следующее направление (буфер)
let score;
let bestScore;
let gameLoop = null;
let isRunning = false;
let isPaused = false;

// Элементы UI
const scoreEl    = document.getElementById('score');
const bestScoreEl= document.getElementById('best-score');
const startBtn   = document.getElementById('start-btn');
const pauseBtn   = document.getElementById('pause-btn');

// ============ ВСПОМОГАТЕЛЬНЫЕ ФУНКЦИИ ============
function randomPosition() {
    return {
        x: Math.floor(Math.random() * TILE_COUNT),
        y: Math.floor(Math.random() * TILE_COUNT)
    };
}

function placeFood() {
    let pos;
    do {
        pos = randomPosition();
    } while (snake.some(seg => seg.x === pos.x && seg.y === pos.y));
    food = pos;
}

// Загрузка рекорда из localStorage
bestScore = parseInt(localStorage.getItem('snakeBest') || '0', 10);
bestScoreEl.textContent = bestScore;

// ============ ЗАПУСК / ПЕРЕЗАПУСК ============
function startGame() {
    if (isRunning) return;          // уже идёт — игнорируем повторный клик

    snake   = [{ x: 10, y: 10 }];  // старт в центре
    direction   = { x: 1, y: 0 };  // движение вправо
    nextDirection = { ...direction };
    score = 0;
    scoreEl.textContent = 0;
    isRunning = true;
    isPaused  = false;
    startBtn.disabled = true;
    pauseBtn.disabled = false;

    placeFood();
    draw();                           // первый кадр
    gameLoop = setInterval(update, INITIAL_SPEED);
}

function resetGame() {
    clearInterval(gameLoop);
    isRunning   = false;
    isPaused    = false;
    startBtn.disabled = false;
    pauseBtn.disabled = true;
    pauseBtn.textContent = 'Пауза';

    // показать надпись "Нажмите Старт"
    ctx.fillStyle = '#eee';
    ctx.font = '28px Segoe UI';
    ctx.textAlign = 'center';
    ctx.fillText('Нажмите Старт', canvas.width / 2, canvas.height / 2);
}

function togglePause() {
    if (!isRunning) return;
    isPaused = !isPaused;
    pauseBtn.textContent = isPaused ? 'Продолжить' : 'Пауза';
    if (isPaused) {
        clearInterval(gameLoop);
    } else {
        gameLoop = setInterval(update, INITIAL_SPEED);
    }
}

// ============ ОСНОВНОЙ ЦИКЛ ОБНОВЛЕНИЯ ============
function update() {
    // Применяем буферизованное направление
    direction = { ...nextDirection };

    const head = { x: snake[0].x + direction.x, y: snake[0].y + direction.y };

    // Столкновение со стеной
    if (head.x < 0 || head.x >= TILE_COUNT || head.y < 0 || head.y >= TILE_COUNT) {
        gameOver();
        return;
    }

    // Столкновение с собой
    if (snake.some(seg => seg.x === head.x && seg.y === head.y)) {
        gameOver();
        return;
    }

    snake.unshift(head);

    // Съели еду?
    if (head.x === food.x && head.y === food.y) {
        score++;
        scoreEl.textContent = score;
        placeFood();
    } else {
        snake.pop();  // нормальное движение — убираем хвост
    }

    draw();
}

// ============ КОНЕЦ ИГРЫ ============
function gameOver() {
    clearInterval(gameLoop);
    isRunning = false;

    // Обновляем рекорд
    if (score > bestScore) {
        bestScore = score;
        localStorage.setItem('snakeBest', bestScore.toString());
        bestScoreEl.textContent = bestScore;
    }

    startBtn.disabled = false;
    pauseBtn.disabled = true;

    // Рисуем "Game Over" поверх поля
    ctx.fillStyle = 'rgba(0, 0, 0, 0.55)';
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    ctx.fillStyle = '#e94560';
    ctx.font = 'bold 32px Segoe UI';
    ctx.textAlign = 'center';
    ctx.fillText('Game Over!', canvas.width / 2, canvas.height / 2 - 16);

    ctx.fillStyle = '#eee';
    ctx.font = '18px Segoe UI';
    ctx.fillText(`Счёт: ${score}`, canvas.width / 2, canvas.height / 2 + 20);
}

// ============ ОТРИСОВКА ============
function draw() {
    // Очищаем поле
    ctx.clearRect(0, 0, canvas.width, canvas.height);

    // Рисуем сетку (тонкие линии)
    ctx.strokeStyle = COLORS.gridLine;
    for (let i = 0; i <= TILE_COUNT; i++) {
        const p = i * GRID_SIZE;
        ctx.beginPath();
        ctx.moveTo(p, 0);
        ctx.lineTo(p, canvas.height);
        ctx.stroke();
        ctx.beginPath();
        ctx.moveTo(0, p);
        ctx.lineTo(canvas.width, p);
        ctx.stroke();
    }

    // Рисуем еду (свечение)
    const fx = food.x * GRID_SIZE + GRID_SIZE / 2;
    const fy = food.y * GRID_SIZE + GRID_SIZE / 2;
    const glow = ctx.createRadialGradient(fx, fy, 2, fx, fy, GRID_SIZE);
    glow.addColorStop(0, COLORS.food);
    glow.addColorStop(1, 'transparent');
    ctx.fillStyle = glow;
    ctx.fillRect(food.x * GRID_SIZE - 5, food.y * GRID_SIZE - 5, GRID_SIZE + 10, GRID_SIZE + 10);

    ctx.fillStyle = COLORS.food;
    ctx.beginPath();
    ctx.arc(fx, fy, GRID_SIZE / 2 - 3, 0, Math.PI * 2);
    ctx.fill();

    // Рисуем змейку
    snake.forEach((seg, i) => {
        const x = seg.x * GRID_SIZE;
        const y = seg.y * GRID_SIZE;
        const radius = 4;

        if (i === 0) {
            // Голова — яркий цвет
            ctx.fillStyle = COLORS.snakeHead;
            ctx.shadowColor = COLORS.snakeHead;
            ctx.shadowBlur = 8;
        } else {
            // Тело — градиент к темноту к хвосту
            const t = i / snake.length;  // 0 у головы, ~1 на хвосте
            ctx.fillStyle = COLORS.snakeBody;
            ctx.shadowBlur = 0;
        }

        // Скруглённый квадрат
        ctx.beginPath();
        ctx.roundRect(x + 1, y + 1, GRID_SIZE - 2, GRID_SIZE - 2, radius);
        ctx.fill();
        ctx.shadowBlur = 0;   // сброс свечения
    });
}

// ============ УПРАВЛЕНИЕ КЛАВИАТУРОЙ ============
const KEY_MAP = {
    ArrowUp:    { x:  0, y: -1 },
    w:          { x:  0, y: -1 },
    W:          { x:  0, y: -1 },
    ArrowDown:  { x:  0, y:  1 },
    s:          { x:  0, y:  1 },
    S:          { x:  0, y:  1 },
    ArrowLeft:  { x: -1, y:  0 },
    a:          { x: -1, y:  0 },
    A:          { x: -1, y:  0 },
    ArrowRight: { x:  1, y:  0 },
    d:          { x:  1, y:  0 },
    D:          { x:  1, y:  0 },
};

document.addEventListener('keydown', (e) => {
    const dir = KEY_MAP[e.key];
    if (!dir) return;

    e.preventDefault();

    // Нельзя развернуться на 180°
    if (dir.x + direction.x === 0 && dir.y + direction.y === 0) return;

    nextDirection = dir;
});

// ============ ОБРАБОТЧИКИ КНОПОК ============
startBtn.addEventListener('click', startGame);
pauseBtn.addEventListener('click', togglePause);

// Начальная отрисовка — экран ожидания
ctx.fillStyle = '#eee';
ctx.font = '28px Segoe UI';
ctx.textAlign = 'center';
ctx.fillText('Нажмите Старт', canvas.width / 2, canvas.height / 2);

